import org.eclipse.rdf4j.rio.RioSetting;
import org.eclipse.rdf4j.rio.helpers.BasicWriterSettings;
import org.eclipse.rdf4j.rio.helpers.RDFJSONWriterSettings;
import org.junit.jupiter.api.Test;

/**
 * JUnit test for the RDF/JSON parser.
 *
 * @author Peter Ansell
 */
public class RDFJSONWriterTest extends RDFWriterTest {

	public RDFJSONWriterTest() {
		super(new RDFJSONWriterFactory(), new RDFJSONParserFactory());
	}

	@Override
	protected Model parse(InputStream reader, String baseURI)
			throws RDFParseException, RDFHandlerException {
		return QueryResults
				.asModel(QueryResults.parseGraphBackground(reader, baseURI, rdfParserFactory.getRDFFormat()
				));
	}

	@Override
	protected RioSetting<?>[] getExpectedSupportedSettings() {
		return new RioSetting[] { BasicWriterSettings.PRETTY_PRINT,
				RDFJSONWriterSettings.ALLOW_MULTIPLE_OBJECT_VALUES,
				BasicWriterSettings.RDF_OUTPUT_VERSION };
	}

	@Test
	public void directedLanguageLiteralRoundTripsBaseDirection() throws Exception {
		ValueFactory vf = SimpleValueFactory.getInstance();
		IRI subject = vf.createIRI("urn:subject");
		IRI predicate = vf.createIRI("urn:predicate");
		Literal literal = vf.createLiteral("שלום", "he", Literal.BaseDirection.RTL);
		Model model = new LinkedHashModel();
		model.add(subject, predicate, literal);

		ByteArrayOutputStream output = new ByteArrayOutputStream();
		Rio.write(model, output, RDFFormat.RDFJSON);
		Model parsed = Rio.parse(new ByteArrayInputStream(output.toByteArray()), "", RDFFormat.RDFJSON);

		Iterator<Value> objects = parsed.filter(subject, predicate, null).objects().iterator();
		Literal parsedLiteral = assertInstanceOf(Literal.class, objects.next());
		assertEquals(literal.getLabel(), parsedLiteral.getLabel());
		assertEquals("he", parsedLiteral.getLanguage().orElseThrow());
		assertEquals(Literal.BaseDirection.RTL, parsedLiteral.getBaseDirection());
		assertEquals(literal, parsedLiteral);
	}

}
